protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Blog>(entity =>
    {
        // EF9 renamed the discriminator property from "Discriminator" to "$type".
        // Keep the old name so existing documents and raw SQL
        // (e.g. WHERE c.Discriminator = 'Blog') continue to work.
        entity.HasDiscriminator<string>("Discriminator")
              .HasValue<Blog>("Blog");

        // EF9 maps a single-string-key Id directly to JSON "id".
        // Force the old shadow "__id" property so the entity's Id stays
        // a plain key value ("1") separate from the Cosmos id ("Blog|1").
        entity.HasShadowId();

        // EF9 no longer prefixes the JSON "id" with the discriminator.
        // Restore the old "Blog|1" format for existing documents.
        entity.HasDiscriminatorInJsonId();

        // EF9 breaking: HasIndex now throws for the Cosmos provider
        // (it was silently ignored before). Removed.
    });
}

